- This query is likely part of a larger system used to manage projects, including the materials and patterns used in each project; 
- The 'length_width_ratio' is likely an important factor in deciding the suitability of a tile pattern for a particular project, as it can affect the overall aesthetic and functionality of the space; 
- Ceramic tiles are a common choice for kitchen remodels due to their durability, ease of maintenance, and resistance to moisture.

sql:
SELECT pattern_description, tile_length, tile_width
FROM tile_patterns
ORDER BY tile_length ASC;

SELECT * 
FROM tile_patterns 
WHERE cost_per_tile > (SELECT AVG(cost_per_tile) FROM tile_patterns);

SELECT COUNT(DISTINCT p.project_id)
FROM projects AS p
INNER JOIN project_patterns AS pp ON p.project_id = pp.project_id;

SELECT COUNT(*)
FROM project_patterns
WHERE installation_date < '2022-12-31';

SELECT 
    (SELECT COUNT(DISTINCT project_id) FROM projects) AS number_of_projects,
    (SELECT COUNT(DISTINCT pattern_id) FROM tile_patterns) AS number_of_patterns;
